"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[294],{433:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","label":"Introduction","href":"/mobx-chunk/docs/intro","docId":"intro","unlisted":false},{"type":"category","label":"Concepts","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Create Chunk","href":"/mobx-chunk/docs/concepts/create-chunk","docId":"concepts/create-chunk","unlisted":false},{"type":"link","label":"Subscribe to Changes","href":"/mobx-chunk/docs/concepts/subscribe-to-changes","docId":"concepts/subscribe-to-changes","unlisted":false},{"type":"link","label":"Persistence Setup","href":"/mobx-chunk/docs/concepts/persistence","docId":"concepts/persistence","unlisted":false},{"type":"link","label":"Middleware Setup","href":"/mobx-chunk/docs/concepts/middleware","docId":"concepts/middleware","unlisted":false},{"type":"link","label":"Queries & Mutations","href":"/mobx-chunk/docs/concepts/queries","docId":"concepts/queries","unlisted":false}],"href":"/mobx-chunk/docs/category/concepts"},{"type":"category","label":"API","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"API: createChunk","href":"/mobx-chunk/docs/api/createChunk","docId":"api/createChunk","unlisted":false},{"type":"link","label":"API: useChunk","href":"/mobx-chunk/docs/api/useChunk","docId":"api/useChunk","unlisted":false},{"type":"link","label":"API: useValues","href":"/mobx-chunk/docs/api/useValues","docId":"api/useValues","unlisted":false},{"type":"link","label":"API: useComputed","href":"/mobx-chunk/docs/api/useComputed","docId":"api/useComputed","unlisted":false},{"type":"link","label":"API: combineAsync","href":"/mobx-chunk/docs/api/combineAsync","docId":"api/combineAsync","unlisted":false},{"type":"link","label":"API: useStoreInitialized","href":"/mobx-chunk/docs/api/useStoreInitialized","docId":"api/useStoreInitialized","unlisted":false},{"type":"link","label":"API: configurePersistenceEngine","href":"/mobx-chunk/docs/api/configurePersistenceEngine","docId":"api/configurePersistenceEngine","unlisted":false},{"type":"link","label":"API: useQuery","href":"/mobx-chunk/docs/api/useQuery","docId":"api/useQuery","unlisted":false},{"type":"link","label":"API: addActionInterceptor / removeActionInterceptor","href":"/mobx-chunk/docs/api/addActionInterceptor","docId":"api/addActionInterceptor","unlisted":false},{"type":"link","label":"API: useInfiniteQuery","href":"/mobx-chunk/docs/api/useInfiniteQuery","docId":"api/useInfiniteQuery","unlisted":false},{"type":"link","label":"API: selectorFn","href":"/mobx-chunk/docs/api/selectorFn","docId":"api/selectorFn","unlisted":false},{"type":"link","label":"API: useMutation","href":"/mobx-chunk/docs/api/useMutation","docId":"api/useMutation","unlisted":false},{"type":"link","label":"API: combineQueries","href":"/mobx-chunk/docs/api/combineQueries","docId":"api/combineQueries","unlisted":false}],"href":"/mobx-chunk/docs/category/api"}]},"docs":{"api/addActionInterceptor":{"id":"api/addActionInterceptor","title":"API: addActionInterceptor / removeActionInterceptor","description":"Register (and unregister) global middleware functions that intercept chunk async actions. Useful for validation, logging, or performance tracking.","sidebar":"tutorialSidebar"},"api/combineAsync":{"id":"api/combineAsync","title":"API: combineAsync","description":"Utility for merging multiple builder functions into a single flat API of asynchronous methods. Each builder receives a shared context (self) and returns an object of async functions; combineAsync binds them into one API, preserving original signatures.","sidebar":"tutorialSidebar"},"api/combineQueries":{"id":"api/combineQueries","title":"API: combineQueries","description":"Utility for merging multiple query builder functions into a single builder. Works identically to combineAsync but for query/mutation/infinite query definitions.","sidebar":"tutorialSidebar"},"api/configurePersistenceEngine":{"id":"api/configurePersistenceEngine","title":"API: configurePersistenceEngine","description":"Global configuration for persisting state fields in mobx-chunk. Plug any storage engine by providing CRUD methods for string-based keys and values.","sidebar":"tutorialSidebar"},"api/createChunk":{"id":"api/createChunk","title":"API: createChunk","description":"Define a self-contained, type-safe MobX store slice (\\"chunk\\") with optional custom logic, persistence, and async support.","sidebar":"tutorialSidebar"},"api/selectorFn":{"id":"api/selectorFn","title":"API: selectorFn","description":"Marks a view function as a parameterized method so it is not treated as a computed getter.","sidebar":"tutorialSidebar"},"api/useChunk":{"id":"api/useChunk","title":"API: useChunk","description":"React hook for creating and managing a local MobX chunk store instance for the lifetime of a component.","sidebar":"tutorialSidebar"},"api/useComputed":{"id":"api/useComputed","title":"API: useComputed","description":"React hook for subscribing to a single MobX chunk-derived value or loading flag. Re-renders your component when the selected value changes.","sidebar":"tutorialSidebar"},"api/useInfiniteQuery":{"id":"api/useInfiniteQuery","title":"API: useInfiniteQuery","description":"React hook for subscribing to a MobX-powered infinite query. Loads the first page on mount, provides fetchNextPage for pagination, and re-renders on state changes.","sidebar":"tutorialSidebar"},"api/useMutation":{"id":"api/useMutation","title":"API: useMutation","description":"React hook for subscribing to a MobX-powered mutation. Provides mutate (fire-and-forget) and mutateAsync (returns Promise), and re-renders when the mutation state changes.","sidebar":"tutorialSidebar"},"api/useQuery":{"id":"api/useQuery","title":"API: useQuery","description":"React hook for subscribing to a MobX-powered query. Auto-fetches on mount (unless disabled), subscribes to observable state, and re-renders the component when data, error, or status changes.","sidebar":"tutorialSidebar"},"api/useStoreInitialized":{"id":"api/useStoreInitialized","title":"API: useStoreInitialized","description":"React hook to defer rendering until specified MobX store instances are initialized. Returns a boolean flag that toggles from false to true immediately after the provided stores are referenced on component mount.","sidebar":"tutorialSidebar"},"api/useValues":{"id":"api/useValues","title":"API: useValues","description":"React hook for batch-subscribing to multiple MobX chunk-derived values in one call. Re-renders your component when any selected value changes.","sidebar":"tutorialSidebar"},"concepts/create-chunk":{"id":"concepts/create-chunk","title":"Create Chunk","description":"The createChunk function is the heart of mobx-chunk, allowing you to define a type-safe store slice (\\"chunk\\") with minimal boilerplate. It automatically generates actions, selectors, async actions, and loading flags based on your configuration and custom definitions.","sidebar":"tutorialSidebar"},"concepts/middleware":{"id":"concepts/middleware","title":"Middleware Setup","description":"mobx-chunk supports action interceptors\u2014middleware functions that run before or after your custom actions and async flows. Use them to add validation, logging, performance monitoring, or any cross-cutting concerns.","sidebar":"tutorialSidebar"},"concepts/persistence":{"id":"concepts/persistence","title":"Persistence Setup","description":"To persist store fields across sessions, mobx-chunk lets you plug in any storage engine via configurePersistenceEngine. Below are examples for React Native (MMKV, AsyncStorage) and web (localStorage).","sidebar":"tutorialSidebar"},"concepts/queries":{"id":"concepts/queries","title":"Queries & Mutations","description":"mobx-chunk includes a built-in data fetching layer \u2014 queries, mutations, and infinite queries \u2014 with per-argument caching, automatic loading/error tracking, and manual invalidation. Think of it as a simplified TanStack Query powered by MobX observables.","sidebar":"tutorialSidebar"},"concepts/subscribe-to-changes":{"id":"concepts/subscribe-to-changes","title":"Subscribe to Changes","description":"mobx-chunk provides easy-to-use React hooks to reactively subscribe to store changes and keep your components in sync.","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Introduction","description":"Welcome to mobx-chunk, a lightweight, type-safe factory for building MobX-powered state slices (\\"chunks\\") with minimal boilerplate. Whether you\u2019re managing simple local state or complex asynchronous flows, mobx-chunk helps you stay organized and scalable.","sidebar":"tutorialSidebar"}}}}')}}]);